func formatCategory(cat models.PatternCategory) string {
	str := string(cat)
	str = strings.ReplaceAll(str, "_", " ")
	// Title case
	words := strings.Split(str, " ")
	for i, word := range words {
		if len(word) > 0 {
			words[i] = strings.ToUpper(word[:1]) + word[1:]
		}
	}
	return strings.Join(words, " ")
}

